int riddle(int n) {
  if (n == 0) return 1;
  if (n == 1) return 1;
  if (n % 2 == 0) return riddle(n/2) + riddle(n/2 - 1);
  return riddle((n-1)/2) + riddle((n+1)/2);
}
A student claims riddle(6) = 13. Her professor says riddle(6) = 5. The TA says riddle(6) = 8.
What is riddle(6)?

What is the output of this function on an empty tree (root = NULL)?
int height(Node* root){
  if(!root) return -1;
  return 1+max(height(root->left),height(root->right));
}

